{
    "level": "A2–B1",
    "intro": "In this topic, you will learn <strong>to distinguish between adjectives and adverbs</strong>, to form them correctly and to use them in sentences.",
    "rules": [
        {
            "label": "Adjectives",
            "color": "emerald",
            "text": "<strong>Adjectives</strong> describe nouns:",
            "example": "a quick answer, She is happy."
        },
        {
            "label": "Adverbs",
            "color": "blue",
            "text": "<strong>Adverbs</strong> describe verbs:",
            "example": "He answered quickly. She smiled happily."
        },
        {
            "label": "Formation",
            "color": "amber",
            "text": "Most adverbs = <em>adjective + -ly</em>:",
            "example": "slow → slowly, careful → carefully"
        }
    ]
}

{
    "title": "1. The main difference",
    "intro": "Adjectives and adverbs answer different questions and describe different parts of speech:",
    "rows": [
        {
            "en": "Adjectives",
            "ua": "Adjectives",
            "note": "Describing nouns (which? which? which?)"
        },
        {
            "en": "Adverbs",
            "ua": "Adverbs",
            "note": "Describing verbs (how? when? where?)"
        },
        {
            "en": "a beautiful dress",
            "ua": "a beautiful dress",
            "note": "adjective → describes dress"
        },
        {
            "en": "She dances beautifully.",
            "ua": "She dances beautifully.",
            "note": "adverb → describes dances"
        }
    ],
    "warning": "💡 Ask yourself: what is being described? If it's a noun, use an adjective, if it's a verb, use an adverb."
}

{
    "title": "2. Formation of adverbs",
    "sections": [
        {
            "label": "General rule: + -ly",
            "color": "emerald",
            "description": "Most adverbs are formed by adding <strong>-ly</strong> to an adjective:",
            "examples": [
                {
                    "en": "quick → quickly",
                    "ua": "quick → quickly"
                },
                {
                    "en": "careful → carefully",
                    "ua": "careful → carefully"
                },
                {
                    "en": "slow → slowly",
                    "ua": "slow → slowly"
                }
            ]
        },
        {
            "label": "Ending in -y → -ily",
            "color": "blue",
            "description": "If the adjective ends in <strong>-y</strong>, change it to <strong>-ily</strong>:",
            "examples": [
                {
                    "en": "happy → happily",
                    "ua": "happy → happily"
                },
                {
                    "en": "easy → easily",
                    "ua": "easy → easily"
                },
                {
                    "en": "angry → angrily",
                    "ua": "angry → angrily"
                }
            ]
        },
        {
            "label": "Ending in -le → -ly",
            "color": "sky",
            "description": "If the adjective ends in <strong>-le</strong>, simply change <strong>-e</strong> to <strong>-y</strong>:",
            "examples": [
                {
                    "en": "simple → simply",
                    "ua": "simple → simply"
                },
                {
                    "en": "gentle → gently",
                    "ua": "gentle → gently"
                },
                {
                    "en": "terrible → terribly",
                    "ua": "terrible → terribly"
                }
            ]
        }
    ]
}

{
    "title": "3. Words with the same form",
    "sections": [
        {
            "label": "Fast, hard, late, early",
            "color": "emerald",
            "description": "Some words have <strong>same form</strong> for adjective and adverb:",
            "examples": [
                {
                    "en": "a fast car / He drives fast.",
                    "ua": "a fast car / He drives fast."
                },
                {
                    "en": "hard work / She works hard.",
                    "ua": "hard work / She works hard."
                },
                {
                    "en": "an early morning / I woke up early.",
                    "ua": "an early morning / I woke up early."
                }
            ]
        },
        {
            "label": "Attention: hardly ≠ hard!",
            "color": "rose",
            "description": "<strong>Hardly</strong> means \"barely, almost not\", not \"difficult\":",
            "examples": [
                {
                    "en": "I can hardly see anything.",
                    "ua": "I can hardly see anything."
                },
                {
                    "en": "She hardly ever calls me.",
                    "ua": "She hardly ever calls me."
                }
            ]
        },
        {
            "label": "Attention: lately ≠ late!",
            "color": "amber",
            "description": "<strong>Lately</strong> means \"lately\", not \"late\":",
            "examples": [
                {
                    "en": "I arrived late. (пізно)",
                    "ua": "I arrived late. (пізно)"
                },
                {
                    "en": "Lately, I have been busy. (останнім часом)",
                    "ua": "Lately, I have been busy. (останнім часом)"
                }
            ]
        }
    ]
}

{
    "title": "4. Good vs Well",
    "intro": "One of the most common mistakes is to confuse <strong>good</strong> (adjective) with <strong>well</strong> (adverb):",
    "rows": [
        {
            "en": "She is a good singer.",
            "ua": "She is a good singer.",
            "note": "✓ the adjective good describes the singer"
        },
        {
            "en": "She sings well.",
            "ua": "She sings well.",
            "note": "✓ the adverb well describes sings"
        },
        {
            "en": "❌ She sings good.",
            "ua": "❌ She sings good.",
            "note": "Required: She sings well."
        },
        {
            "en": "❌ She is a well singer.",
            "ua": "❌ She is a well singer.",
            "note": "Required: She is a good singer."
        }
    ],
    "warning": "💡 <strong>Well</strong> as an adjective means \"healthy\": I feel well today."
}

{
    "title": "5. Position in the sentence",
    "sections": [
        {
            "label": "Adjectives",
            "color": "emerald",
            "description": "Adjectives are <strong>before the noun</strong> or <strong>after to be / linking verbs</strong>:",
            "examples": [
                {
                    "en": "an expensive car (перед іменником)",
                    "ua": "an expensive car (перед іменником)"
                },
                {
                    "en": "The car is expensive. (після to be)",
                    "ua": "The car is expensive. (після to be)"
                },
                {
                    "en": "The soup smells delicious. (після linking verb)",
                    "ua": "The soup smells delicious. (після linking verb)"
                }
            ]
        },
        {
            "label": "Adverbs",
            "color": "blue",
            "description": "Adverbs usually come <strong>after the verb</strong> or <strong>at the end of the sentence</strong>:",
            "examples": [
                {
                    "en": "He speaks clearly.",
                    "ua": "He speaks clearly."
                },
                {
                    "en": "She answered the question correctly.",
                    "ua": "She answered the question correctly."
                },
                {
                    "en": "They drive carefully.",
                    "ua": "They drive carefully."
                }
            ]
        },
        {
            "label": "Adverbs of frequency",
            "color": "sky",
            "description": "Adverbs of frequency (always, usually, often) stand <strong>before the main verb</strong>:",
            "examples": [
                {
                    "en": "I always wake up early.",
                    "ua": "I always wake up early."
                },
                {
                    "en": "She never drinks coffee.",
                    "ua": "She never drinks coffee."
                }
            ]
        }
    ]
}

{
    "title": "6. Typical mistakes",
    "sections": [
        {
            "label": "Mistake 1: Real / Really",
            "color": "rose",
            "description": "<strong>Real</strong> is an adjective, <strong>really</strong> is an adverb (really, very):",
            "examples": [
                {
                    "en": "✓ This is a real diamond. (справжній діамант)",
                    "ua": "✓ This is a real diamond. (справжній діамант)"
                },
                {
                    "en": "✓ I really like this song. (дійсно подобається)",
                    "ua": "✓ I really like this song. (дійсно подобається)"
                },
                {
                    "en": "❌ I real like this. → ✓ I really like this.",
                    "ua": "❌ I real like this. → ✓ I really like this."
                }
            ]
        },
        {
            "label": "Error 2: Bad / Badly",
            "color": "rose",
            "description": "<strong>Bad</strong> is an adjective (bad), <strong>badly</strong> is an adverb (bad):",
            "examples": [
                {
                    "en": "✓ I feel bad. (почуваюся погано)",
                    "ua": "✓ I feel bad. (почуваюся погано)"
                },
                {
                    "en": "✓ He played badly. (грав погано)",
                    "ua": "✓ He played badly. (грав погано)"
                },
                {
                    "en": "❌ He played bad. → ✓ He played badly.",
                    "ua": "❌ He played bad. → ✓ He played badly."
                }
            ]
        },
        {
            "label": "Error 3: After linking verbs",
            "color": "amber",
            "description": "After <strong>linking verbs</strong> (feel, look, smell, taste, sound) we use <strong>adjective</strong>:",
            "examples": [
                {
                    "en": "✓ The food tastes good. (не goodly)",
                    "ua": "✓ The food tastes good. (не goodly)"
                },
                {
                    "en": "✓ You look tired. (не tiredly)",
                    "ua": "✓ You look tired. (не tiredly)"
                },
                {
                    "en": "✓ This sounds interesting. (не interestingly)",
                    "ua": "✓ This sounds interesting. (не interestingly)"
                }
            ]
        }
    ]
}

{
    "title": "7. Change of value with -ly",
    "intro": "Some words have different meanings as an adjective and as an adverb with -ly:",
    "rows": [
        {
            "en": "hard / hardly",
            "ua": "hard / hardly",
            "note": "He works hard. / He hardly works."
        },
        {
            "en": "late / lately",
            "ua": "late / lately",
            "note": "I arrived late. / Lately, I am busy."
        },
        {
            "en": "near / nearly",
            "ua": "near / nearly",
            "note": "Come near. / I nearly forgot."
        },
        {
            "en": "high / highly",
            "ua": "high / highly",
            "note": "Fly high. / Highly recommended."
        },
        {
            "en": "short / shortly",
            "ua": "short / shortly",
            "note": "Cut it short. / I will call shortly."
        }
    ],
    "warning": "💡 Always check the meaning of the word with -ly in the dictionary — it may differ from the base adjective!"
}

{
    "title": "8. Practical advice",
    "intro": "How to determine whether to use an adjective or an adverb:",
    "items": [
        {
            "label": "Step 1",
            "title": "Define what is being described",
            "subtitle": "Noun → adjective. Verb → adverb."
        },
        {
            "label": "Step 2",
            "title": "Ask a question",
            "subtitle": "Which? Which one? → adjective. As? → adverb."
        },
        {
            "label": "Step 3",
            "title": "Check the form",
            "subtitle": "Most adverbs end in -ly."
        },
        {
            "label": "Step 4",
            "title": "Remember the exceptions",
            "subtitle": "fast, hard, early, late are the same forms!"
        }
    ]
}

{
    "title": "9. Additional cases",
    "sections": [
        {
            "label": "Adverbs describing adjectives",
            "color": "emerald",
            "description": "Adverbs can describe <strong>adjectives</strong> to strengthen or weaken:",
            "examples": [
                {
                    "en": "It is extremely hot today.",
                    "ua": "It is extremely hot today."
                },
                {
                    "en": "She is very beautiful.",
                    "ua": "She is very beautiful."
                },
                {
                    "en": "This is quite interesting.",
                    "ua": "This is quite interesting."
                }
            ]
        },
        {
            "label": "Adverbs describing adverbs",
            "color": "blue",
            "description": "Adverbs can describe other <strong>adverbs</strong>:",
            "examples": [
                {
                    "en": "He drives very carefully.",
                    "ua": "He drives very carefully."
                },
                {
                    "en": "She speaks extremely quickly.",
                    "ua": "She speaks extremely quickly."
                },
                {
                    "en": "They work surprisingly well together.",
                    "ua": "They work surprisingly well together."
                }
            ]
        }
    ]
}
